    """Discover available CorpusAdapter subclasses from the adapters package."""
    from noosphere.external_battery import CorpusAdapter
    import importlib
    import pkgutil
    try:
        pkg = importlib.import_module("noosphere.external_battery.adapters")
    except ImportError:
